```java
import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import io.github.resilience4j.retry.annotation.Retry;
import org.springframework.stereotype.Service;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class TradeService {
    private final MarketServiceClient marketClient;
    // Simple price cache for fallback:
    private final Map<String, Double> priceCache = new ConcurrentHashMap<>();

    TradeService(MarketServiceClient mc) { marketClient = mc; }

    @CircuitBreaker(name = "market-service", fallbackMethod = "getQuoteFallback")
    @Retry(name = "market-service")
    public StockQuote getQuote(String symbol) {
        StockQuote quote = marketClient.getQuote(symbol);
        priceCache.put(symbol, quote.price());  // update cache on success
        return quote;
    }

    // Fallback: returns cached price, tradeable=false
    public StockQuote getQuoteFallback(String symbol, Exception ex) {
        double cachedPrice = priceCache.getOrDefault(symbol, 0.0);
        System.out.printf("[FALLBACK] %s: using cached price %.2f | %s%n",
            symbol, cachedPrice, ex.getClass().getSimpleName());
        return new StockQuote(symbol, cachedPrice, false);
    }

    public TradeConfirmation executeTrade(String userId, String symbol, int qty) {
        StockQuote quote = getQuote(symbol);
        if (!quote.tradeable()) {
            throw new MarketUnavailableException(
                "Market unavailable for " + symbol + " — using cached price");
        }
        return new TradeConfirmation(userId, symbol, qty, quote.price());
    }
}
```

