@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.NONE)
@TestPropertySource(properties = {
    "eureka.client.enabled=false",
    // Low thresholds for testing:
    "resilience4j.circuitbreaker.instances.market-service.sliding-window-size=5",
    "resilience4j.circuitbreaker.instances.market-service.minimum-number-of-calls=3",
    "resilience4j.circuitbreaker.instances.market-service.failure-rate-threshold=60",
    "resilience4j.circuitbreaker.instances.market-service.wait-duration-in-open-state=2s"
})
class CircuitBreakerTest {
    @MockBean MarketServiceClient marketClient;
    @Autowired TradeService tradeService;
    @Autowired CircuitBreakerRegistry registry;

    @BeforeEach void resetCircuit() {
        registry.circuitBreaker("market-service").reset();
    }

    @Test void fallback_calledWhenServiceFails() {
        when(marketClient.getQuote(anyString()))
            .thenThrow(new RuntimeException("Connection refused"));
        StockQuote quote = tradeService.getQuote("TCS");
        assertEquals("TCS", quote.symbol());
        assertFalse(quote.tradeable());  // fallback returns tradeable=false
    }

    @Test void circuit_opensAfterThresholdFailures() throws Exception {
        when(marketClient.getQuote(anyString()))
            .thenThrow(new RuntimeException("Service down"));
        // Trigger 5 failures (above minimum-calls=3 and threshold=60%):
        for (int i = 0; i < 5; i++) tradeService.getQuote("TCS");
        var cb = registry.circuitBreaker("market-service");
        assertEquals(CircuitBreaker.State.OPEN, cb.getState());
        // Now call — fallback returned without calling marketClient:
        verify(marketClient, atMost(5)).getQuote(any());
    }
}
```

